import pytest

def fizzbuzz(n: int) -> str:
    if n % 15 == 0:
        return 'FizzBuzz'
    elif n % 3 == 0:
        return 'Fizz'
    elif n % 5 == 0:
        return 'Buzz'
    return str(n)

# Happy path tests
@pytest.mark.parametrize("n, expected", [
    (1, "1"),
    (2, "2"),
    (3, "Fizz"),
    (4, "4"),
    (5, "Buzz"),
    (6, "Fizz"),
    (10, "Buzz"),
    (15, "FizzBuzz"),
    (30, "FizzBuzz"),
    (45, "FizzBuzz"),
])
def test_fizzbuzz_happy_path(n, expected):
    assert fizzbuzz(n) == expected

# Edge cases
@pytest.mark.parametrize("n, expected", [
    (0, "FizzBuzz"),  # 0 is divisible by 15
    (-1, "-1"),       # Negative non-multiple
    (-3, "Fizz"),     # Negative multiple of 3
    (-5, "Buzz"),     # Negative multiple of 5
    (-15, "FizzBuzz"), # Negative multiple of 15
])
def test_fizzbuzz_edge_cases(n, expected):
    assert fizzbuzz(n) == expected

# Error cases
@pytest.mark.parametrize("n", [
    "string",  # Non-integer type
    3.5,       # Float
    None,      # None type
    [1, 2, 3], # List
])
def test_fizzbuzz_error_cases(n):
    with pytest.raises(TypeError):
        fizzbuzz(n)
